class DSU {
    int[] par;
    int[] rank;
    int size;

    public DSU(int n) {
        par = new int[n];
        rank = new int[n];
        for (int i = 0; i < n; i++) {
            par[i] = i;
        }
        size = n;
    }

    public int find(int u) {
        if (u != par[u]) {
            par[u] = find(par[u]);
        }
        return par[u];
    }

    public boolean union(int u, int v) {
        int uu = find(u);
        int vv = find(v);
        if (uu == vv) {
            return false;
        }
        if (rank[uu] > rank[vv]) {
            par[vv] = uu;
        } else if (rank[vv] > rank[uu]) {
            par[uu] = vv;
        } else {
            par[uu] = vv;
            rank[vv]++;
        }
        size--;
        return true;
    }
}

class Solution {
    public int findCircleNum(int[][] G) {
        int n = G.length;
        DSU uf = new DSU(n);
        if (n == 0) return 0;

        for (int u = 0; u < n; u++) {
            for (int v = 0; v < n; v++) {
                if (G[u][v] == 1) {
                    uf.union(u, v);
                }
            }
        }

        return uf.size;
    }
}
